CREATE TABLE `lich_hoc` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `ngay_hoc` date NOT NULL,
  `tiet_bat_dau` int unsigned NOT NULL,
  `tiet_ket_thuc` int unsigned NOT NULL,
  `trang_thai` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `ghi_chu` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `ngay_tao` datetime(6) NOT NULL,
  `phong_hoc_id` bigint NOT NULL,
  `giang_vien_id` bigint NOT NULL,
  `ma_lop` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `mon_hoc_id` bigint DEFAULT NULL,
  `si_so` int unsigned NOT NULL,
  `lop_hoc_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `lich_hoc_phong_hoc_id_4575053a_fk_phong_hoc_id` (`phong_hoc_id`),
  KEY `lich_hoc_giang_vien_id_fc2a1dad_fk_nguoi_dung_id` (`giang_vien_id`),
  KEY `lich_hoc_mon_hoc_id_a71df9b3_fk_mon_hoc_id` (`mon_hoc_id`),
  KEY `lich_hoc_lop_hoc_id_21fd63f4_fk_lop_hoc_id` (`lop_hoc_id`),
  CONSTRAINT `lich_hoc_giang_vien_id_fc2a1dad_fk_nguoi_dung_id` FOREIGN KEY (`giang_vien_id`) REFERENCES `nguoi_dung` (`id`),
  CONSTRAINT `lich_hoc_lop_hoc_id_21fd63f4_fk_lop_hoc_id` FOREIGN KEY (`lop_hoc_id`) REFERENCES `lop_hoc` (`id`),
  CONSTRAINT `lich_hoc_mon_hoc_id_a71df9b3_fk_mon_hoc_id` FOREIGN KEY (`mon_hoc_id`) REFERENCES `mon_hoc` (`id`),
  CONSTRAINT `lich_hoc_phong_hoc_id_4575053a_fk_phong_hoc_id` FOREIGN KEY (`phong_hoc_id`) REFERENCES `phong_hoc` (`id`),
  CONSTRAINT `lich_hoc_chk_1` CHECK ((`tiet_bat_dau` >= 0)),
  CONSTRAINT `lich_hoc_chk_2` CHECK ((`tiet_ket_thuc` >= 0)),
  CONSTRAINT `lich_hoc_chk_3` CHECK ((`si_so` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=2118 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
